// // This module generates a phase value based on the input frequency number, block identifier, and a multiplication factor. It operates in a synchronous digital system, utilizing a clock signal and a reset signal. The module's primary function is to accumulate a phase count that is modifiable by the input parameters, which can be used in applications such as phase-locked loops (PLLs), digital frequency synthesis, or any system requiring phase adjustment or generation based on dynamic inputs. The output phase is a subset of the internal count, allowing for a wide range of phase adjustments.
module sq_pg(
	input clk,
	input reset_n,
	input [10:0] fnumber,
	input [2:0] block,
  input [3:0] multiple,
  input ce_n, 
	output [9:0]phase );
reg [19:0] count;
assign phase = count[19:10];
wire [19:0]fmult = fnumber << (block-1);
always @(posedge clk or negedge reset_n ) begin
	if( !reset_n )
		count <= 20'b0;
	else begin
	  if( !ce_n )
  	  count <= count + ( multiple==4'b0 ? fmult>> 1 : fmult*multiple);
  	else 
  	  count <= count;
	end
end
endmodule
